def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            if capacity == 0:
                priorities[i] = np.inf if item > 0 else 0
            else:
                priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if ratio == 0:
            priorities[i] = 0
            continue
        score = 0
        penalty = 0
        decay_factor = 1.0
        bonus = 0
        if ratio > 3:
            for p in range(1, 7):
                penalty += ((-1) ** p) * (ratio ** (p + 2)) / (p ** 2 + 1)
            score = (ratio ** 5) - penalty * 1.5
            if capacity > item * 4:
                score /= (capacity / (item + 0.1))
                decay_factor = 0.7
        elif 2 < ratio <= 3:
            for q in range(3, 8):
                score += ((-1) ** q) * (ratio ** q) / (q + 0.3)
            penalty = (ratio ** 2.5) / 3 + np.log1p(ratio)
            score += penalty
            decay_factor = 0.9
        elif 1 < ratio <= 2:
            score = (ratio ** 4) * 1.2
            for r in range(1, 5):
                mult = -1 if r % 2 == 0 else 1
                score += mult * (ratio ** r) / (r + 0.1)
                if r == 3 and ratio > 1.5:
                    bonus += 0.5 * (ratio ** 1.5)
        else:
            for s in range(1, 10):
                sign = 1 if (s % 4 == 0 or s % 5 == 0) else -1
                score += sign * (ratio ** s) / (s + 0.7)
            if ratio < 0.3:
                for t in range(1, 6):
                    penalty += (ratio ** t) / (t * 2 + 0.5)
                score += penalty * 2
                decay_factor = 1.3
            elif ratio < 0.6:
                for u in range(2, 7):
                    score -= ((ratio ** u) / (u + 2)) * (1 if u % 2 == 0 else -1)
                decay_factor = 1.1
            elif ratio < 0.9:
                for v in range(1, 6):
                    add_term = (ratio ** v) / (v + 0.8)
                    score += add_term if v % 2 == 0 else -add_term
                if ratio > 0.75:
                    bonus += 0.7 * (ratio ** 2)
            else:
                for w in range(3, 9):
                    score += ((-1) ** (w + 1)) * (ratio ** w) / (w * 1.2)
                extra = sum((ratio ** n) / (n + 0.4) for n in range(1, 6))
                score += extra * 0.8
                decay_factor = 0.8
        score = max(score + bonus, 0) * decay_factor
        if abs(capacity - item) < 1e-8:
            score += 6 + np.sin(ratio * np.pi)
        if score < 0:
            score = 0
        priorities[i] = score
    return priorities
